function reactive(obj, onChange) {
  return new Proxy(obj, {
    set(target, prop, value) {
      target[prop] = value;
      onChange(prop, value);
      return true;
    }
  });
}

const person = reactive({ name: 'Bob', age: 25 }, (prop, value) => {
  console.log(`Property '${prop}' changed to '${value}'`);
});

person.name = 'Robert'; // Logs property change
person.age = 26;

const dependentsMap = new WeakMap();
let activeEffect = null;

function track(target, prop) {
  if (!activeEffect) return;
  let depsMap = dependentsMap.get(target);
  if (!depsMap) {
    depsMap = new Map();
    dependentsMap.set(target, depsMap);
  }
  let deps = depsMap.get(prop);
  if (!deps) {
    deps = new Set();
    depsMap.set(prop, deps);
  }
  deps.add(activeEffect);
}

function trigger(target, prop) {
  const depsMap = dependentsMap.get(target);
  if (!depsMap) return;
  const deps = depsMap.get(prop);
  if (!deps) return;
  deps.forEach(effect => effect());
}

function reactive(obj) {
  return new Proxy(obj, {
    get(target, prop) {
      track(target, prop);
      return target[prop];
    },
    set(target, prop, value) {
      target[prop] = value;
      trigger(target, prop);
      return true;
    }
  });
}

function effect(fn) {
  activeEffect = fn;
  fn();
  activeEffect = null;
}

// Usage
const state = reactive({ count: 0 });

effect(() => {
  console.log(`Count is: ${state.count}`);
});

state.count = 1; // Automatically logs updated count
state.count = 2;

